    }
}

private String handleKeyTypes(Node n, Node parent) {
    if (parent != null && parent.isObjectLit()) {
        return getNameForObjLitKey(n);
    }
    return null;
}

private Name.Type determineTypeForKey(Node n) {
    switch (n.getType()) {
        case Token.STRING_KEY:
            return getValueType(n.getFirstChild());
        case Token.GETTER_DEF:
            return Name.Type.GET;
        case Token.SETTER_DEF:
            return Name.Type.SET;
        default:
            throw new IllegalStateException("Unexpected node type: " + n);
    }
}

private boolean handleNameTypes(Node n, Node parent) {
    if (parent != null) {
        switch (parent.getType()) {
            case Token.VAR:
                return true; // a variable declaration
            case Token.ASSIGN:
                if (parent.getFirstChild() == n) {
                    return true; // variable assignment
                }
                break;
            case Token.FUNCTION:
                if (parent.getParent() != null && !NodeUtil.isFunctionExpression(parent)) {
                    return true; // function declaration
                }
                break;
            case Token.INC:
            case Token.DEC:
                return true; // increment or decrement
            default:
                return NodeUtil.isAssignmentOp(parent) && parent.getFirstChild() == n;
        }
    }
    return false;
}

private Name.Type determineTypeForName(Node n, Node parent) {
    Node rvalue = n.getFirstChild();
    return (rvalue == null) ? Name.Type.OTHER : getValueType(rvalue);
}

private String handleGetPropTypes(Node n, Node parent) {
    String qualifiedName = n.getQualifiedName();
    if (qualifiedName == null) return null;

    if (parent != null && (parent.getType() == Token.ASSIGN || NodeUtil.isAssignmentOp(parent))) {
        return qualifiedName; // for assignments
    }
    return qualifiedName;
}

private boolean handleGetPropAssignment(Node n, Node parent, boolean isPropAssign) {
    if (parent != null && parent.getType() == Token.ASSIGN && parent.getFirstChild() == n) {
        isPropAssign = true; // property assignment
        return true;
